 77→const loadUniversePostsFallback = async(minX, maxX, minY, maxY, limit) => {
 78→    const settledQuery = supabase
 79→        .from('journals')
 80→        .select(UNIVERSE_POST_SELECT)
 81→        .eq('privacy', 'public')
 82→        .not('settled_x', 'is', null)
 83→        .not('settled_y', 'is', null)
 84→        .gte('settled_x', minX)
 85→        .lte('settled_x', maxX)
 86→        .gte('settled_y', minY)
 87→        .lte('settled_y', maxY)
 88→        .order('created_at', {ascending: false})
 89→        .limit(limit);
 90→
 91→    const unsettledQuery = supabase
 92→        .from('journals')
 93→        .select(UNIVERSE_POST_SELECT)
 94→        .eq('privacy', 'public')
 95→        .is('settled_x', null)
 96→        .is('settled_y', null)
 97→        .gte('universe_x', minX)
 98→        .lte('universe_x', maxX)
 99→        .gte('universe_y', minY)
100→        .lte('universe_y', maxY)
101→        .order('created_at', {ascending: false})
102→        .limit(limit);
103→
104→    const [
105→        {data: settledData, error: settledError},
106→        {data: unsettledData, error: unsettledError}
107→    ] = await Promise.all([settledQuery, unsettledQuery]);
108→
109→    if(settledError || unsettledError){
110→        console.error(
111→            'supabase fallback error while fetching universe posts:',
112→            settledError?.message || unsettledError?.message
113→        );
114→        throw {status: 500, error: 'failed to fetch universe posts'};
115→    }
116→
117→    const mergedById = new Map();
118→    const mergedRows = [...(settledData || []), ...(unsettledData || [])];
119→    for (const row of mergedRows) {
120→        if(!row?.id || mergedById.has(row.id)){
121→            continue;
122→        }
123→
124→        mergedById.set(row.id, normalizeUniversePost(row));
125→        if(mergedById.size >= limit){
126→            break;
127→        }
128→    }
129→
130→    return Array.from(mergedById.values());
131→};
